import React, { useState } from "react";
import { BrowserRouter, Routes, Route, useLocation } from "react-router-dom";

import ScrollToTop from "./components/ScrollToTop";
import Navbar from "./components/Navbar";
import Sidebar from "./components/Sidebar";

import Dashboard from "./components/Dashboard";
import BMI from "./components/BMI";
import AITrainer from "./components/AITrainer";
import Progress from "./components/Progress";
import Recommendation from "./components/Recommendation";

import ChatbotPage from "./components/ChatbotPage";
import ProfilePage from "./components/ProfilePage";
import WorkoutPlans from "./components/WorkoutPlans";

function AppContent() {
  const [darkMode, setDarkMode] = useState(true);
  const location = useLocation();

  const getPageClass = () => {
    if (location.pathname === "/" || location.pathname === "/dashboard") {
      return "page-dashboard";
    }
    if (location.pathname === "/bmi") {
      return "page-bmi";
    }
    if (location.pathname === "/trainer") {
      return "page-trainer";
    }
    if (location.pathname === "/chatbot") {
      return "page-chatbot";
    }
    if (location.pathname === "/recommendation") {
      return "page-recommendation";
    }
    if (location.pathname === "/progress") {
      return "page-progress";
    }
    if (location.pathname === "/profile") {
      return "page-profile";
    }
    if (location.pathname === "/plans") {
      return "page-plans";
    }
    return "page-dashboard";
  };

  return (
    <div className={`${darkMode ? "app-shell dark-theme" : "app-shell light-theme"} ${getPageClass()}`}>
      <ScrollToTop />
      <Navbar />

      <div className="layout">
        <Sidebar darkMode={darkMode} setDarkMode={setDarkMode} />

        <div className="main-content">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/bmi" element={<BMI />} />
            <Route path="/trainer" element={<AITrainer />} />
            <Route path="/progress" element={<Progress />} />
            <Route path="/recommendation" element={<Recommendation />} />
            <Route path="/chatbot" element={<ChatbotPage />} />
            <Route path="/profile" element={<ProfilePage />} />
            <Route path="/plans" element={<WorkoutPlans />} />
          </Routes>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <AppContent />
    </BrowserRouter>
  );
}

export default App;
